Care to comment on this code. Is it good or would you recommend improvements : import { parseWithZod } from "@conform-to/zod";
import CardWrapper from "~/shared/components/CardWrapper";
import { insertAssetSchema } from "~/store/db/schema";
import type { Route } from "./+types/assets-edit";
import { redirect } from "react-router";
import EditPageHeader from "~/shared/components/settings/EditPageHeader";
import AssetForm from "./components/AssetForm";
import { API } from "~/store";

export async function action({ request }: Route.ActionArgs) {
  const formData = await request.formData();

  try {
    const submission = parseWithZod(formData, {
      schema: insertAssetSchema,
    });
    if (submission.status !== "success") {
      return submission.reply();
    }
    const { name, description, isActive } = submission.value;

    const data = {
      name,
      description,
      isActive: isActive === undefined ? false : isActive,
    };

    API.assetRepository.create(data);

    return redirect("../settings/assets");
  } catch (error: unknown) {
    throw new Error(error as string);
  }
}

export default function AssetCreatePage() {
  const backLink = "../settings/assets";
  return (
    <div className="max-w-6xl space-y-8">
      <EditPageHeader backLink={backLink} />
      <CardWrapper>
        <AssetForm />
      </CardWrapper>
    </div>
  );
}


